const InteractiveExhibit = () => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);

  const generate = () => {
    setIsGenerating(true);
    setProgress(0);
    setLogs(["Initializing verification engine...", "Scanning bio-medical records...", "Checking meeting attendance logs..."]);

    let current = 0;
    const interval = setInterval(() => {
      current += Math.random() * 15;
      if (current >= 100) {
        current = 100;
        clearInterval(interval);
        setTimeout(() => {
          setIsGenerating(false);
          setLogs(prev => [...prev, "✓ VERIFICATION COMPLETE", "Exhibit Generated for Case FDSJ-739"]);
        }, 1000);
      }
      setProgress(current);
      if (current > 40 && logs.length === 3) setLogs(prev => [...prev, "External records match provided data..."]);
      if (current > 75 && logs.length === 4) setLogs(prev => [...prev, "Applying Benchmark of Stability filter..."]);
    }, 200);
  };

  return (
    <div className="bg-royal-950 text-royal-100 p-8 rounded-[2rem] border border-royal-900 shadow-2xl space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h3 className="text-xl font-display font-bold text-white uppercase tracking-widest">Exhibit Generator</h3>
           <p className="text-xs text-royal-400 font-mono tracking-tighter">AUTOMATED COMPLIANCE MONITORING</p>
        </div>
        <button 
          onClick={generate}
          disabled={isGenerating}
          className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold transition-all ${isGenerating ? 'bg-royal-800 text-royal-500' : 'bg-gold-600 text-white hover:bg-gold-500 active:scale-95 shadow-lg shadow-gold-500/20'}`}
        >
          {isGenerating ? <RefreshCw className="animate-spin" size={18} /> : <Zap size={18} />}
          {isGenerating ? 'VERIFYING...' : 'RUN VERIFICATION'}
        </button>
      </div>

      <div className="space-y-3 font-mono text-[10px] h-40 overflow-y-auto bg-black/40 p-4 rounded-xl border border-white/5 custom-scrollbar">
         {logs.map((log, i) => (
           <div key={i} className={`${log.startsWith('✓') ? 'text-emerald-400 font-bold' : 'text-royal-300'} animate-in fade-in slide-in-from-left-2`}>
             {`> ${log}`}
           </div>
         ))}
         {isGenerating && <div className="text-gold-500 animate-pulse">_</div>}
      </div>

      <div className="space-y-2">
         <div className="flex justify-between text-[10px] font-bold uppercase text-royal-400 tracking-widest">
            <span>Progress Status</span>
            <span>{Math.round(progress)}%</span>
         </div>
         <div className="h-1.5 bg-royal-900 rounded-full overflow-hidden border border-royal-800/50">
            <div className="h-full bg-emerald-500 transition-all duration-300" style={{ width: `${progress}%` }}></div>
         </div>
      </div>
    </div>
  );
};

