                </div>
             </div>

             <aside className="w-full lg:w-[500px] bg-slate-50 border-l border-slate-200 p-12 overflow-y-auto space-y-10 shadow-[-20px_0_60px_rgba(0,0,0,0.02)] z-10 custom-scrollbar">
                <div className="flex items-center gap-3 mb-10">
                   <div className="h-2 w-2 bg-gold-500 rounded-full"></div>
                   <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Contextual Insights</h3>
                </div>
                {AGREEMENT_PAGES[readerPage].sidebar.map((item, idx) => (
                  <SidebarCard key={idx} item={item} />
                ))}
             </aside>
          </div>

          {/* Reader Footer Controls */}
          <div className="bg-white border-t border-slate-100 p-8 flex justify-between items-center px-16 shadow-[0_-10px_40px_rgba(0,0,0,0.04)]">
             <button 
               onClick={() => {
                 setReaderPage(p => Math.max(0, p - 1));
                 document.querySelector('.flex-1.overflow-y-auto')?.scrollTo(0, 0);
               }} 
               disabled={readerPage === 0} 
               className="flex items-center gap-3 px-12 py-5 rounded-2xl font-black text-xs uppercase tracking-widest border border-slate-100 hover:bg-slate-50 transition-all disabled:opacity-20 active:scale-95 group"
             >
                <ChevronLeft size={20} className="transition-transform group-hover:-translate-x-1" /> Back
             </button>
             <div className="flex gap-4">
               {AGREEMENT_PAGES.map((_, i) => (
                 <div 
                   key={i} 
                   onClick={() => setReaderPage(i)}
                   className={`h-2 rounded-full cursor-pointer transition-all duration-700 ${i === readerPage ? 'bg-royal-950 w-16 shadow-[0_4px_12px_rgba(16,42,67,0.3)]' : 'bg-slate-200 w-4 hover:bg-slate-300'}`}
                 ></div>
               ))}
             </div>
             <button 
               onClick={() => {
                 setReaderPage(p => Math.min(AGREEMENT_PAGES.length - 1, p + 1));
                 document.querySelector('.flex-1.overflow-y-auto')?.scrollTo(0, 0);
               }} 
               disabled={readerPage === AGREEMENT_PAGES.length - 1} 
               className="flex items-center gap-3 px-12 py-5 bg-royal-950 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-royal-800 transition-all shadow-2xl active:scale-95 group"
             >
                Continue <ChevronRight size={20} className="transition-transform group-hover:translate-x-1" />
             </button>
          </div>
        </div>
      )}

      {/* Lexicon / Glossary Modal */}
      {showGlossary && (
        <div className="fixed inset-0 z-[70] flex justify-end">
          <div className="absolute inset-0 bg-royal-950/60 backdrop-blur-xl transition-opacity" onClick={() => setShowGlossary(false)}></div>
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl p-16 overflow-y-auto animate-in slide-in-from-right duration-700 flex flex-col custom-scrollbar">
            <div className="flex justify-between items-center mb-16">
              <div>
                <h3 className="text-xs font-black text-gold-600 uppercase tracking-[0.4em] mb-2">Internal Lexicon</h3>
                <h2 className="text-4xl font-serif font-black text-royal-950 tracking-tight">The Agreement Terms</h2>
              </div>
              <button 
                onClick={() => setShowGlossary(false)} 
                className="p-3 bg-slate-100 hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all active:scale-90"
              >
                <X size={32} />
              </button>
            </div>
            <div className="space-y-10 flex-1">
              {GLOSSARY_TERMS.map((item, idx) => (
                <div key={idx} className="pb-10 border-b border-slate-100 last:border-0 group animate-in fade-in slide-in-from-bottom-4" style={{ animationDelay: `${idx * 100}ms` }}>
                  <h4 className="font-black text-royal-950 text-2xl mb-3 flex justify-between items-center group-hover:text-gold-600 transition-colors">
                    {item.term}
                    <div className="h-px flex-1 mx-4 bg-slate-100 group-hover:bg-gold-100 transition-colors"></div>
                  </h4>
                  <p className="text-slate-500 text-lg leading-relaxed font-medium">{item.definition}</p>
                </div>
              ))}
            </div>
            <div className="mt-20 pt-10 border-t border-slate-100">
               <div className="bg-royal-50 p-8 rounded-3xl border border-royal-100">
                  <div className="flex items-center gap-3 mb-4">
                     <Info className="text-royal-400" size={24} />
                     <h5 className="font-black text-royal-900 uppercase text-xs tracking-widest">Protocol Notice</h5>
                  </div>
                  <p className="text-sm text-royal-700/70 font-medium">These terms are legally binding definitions within the context of the FDSJ-739 directive. Any ambiguity should be resolved by referencing the Harper Baseline core documentation.</p>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
